+      const sidebarRect = document.querySelector(".sidebar")?.getBoundingClientRect();
+      return {
+        view: element?.getAttribute("data-nav-view") || "",
+        visibleAfterFocus: Boolean(rect && sidebarRect && rect.right > sidebarRect.left && rect.left < sidebarRect.right && rect.bottom > sidebarRect.top && rect.top < sidebarRect.bottom),
+      };
+    });
+    forward.push(active);
+    assertCondition(active.view === view && active.visibleAfterFocus, "Tab did not reach a visible mobile navigation route in order", { active, expected, forward });
+    await page.keyboard.press("Enter");
+    await page.waitForSelector(`.content-grid[data-view="${view}"]`, { timeout: 5000 });
+  }
+
+  const reverse = [];
+  for (const view of [...expected].reverse().slice(1)) {
+    await page.keyboard.press("Shift+Tab");
+    const active = await page.evaluate(() => ({
+      view: document.activeElement?.getAttribute("data-nav-view") || "",
+    }));
+    reverse.push(active.view);
+    assertCondition(active.view === view, "Shift+Tab did not traverse mobile navigation in reverse order", { active, expected, reverse });
+  }
+  await page.keyboard.press("Enter");
+  await page.waitForSelector('.content-grid[data-view="home"]', { timeout: 5000 });
+  return { forward, reverse, skipped: false };
+}
