const repo="[REDACTED_LOCAL_PATH]";
const paths={
validator:"OpenAIDatabase/apps/memory-atlas/scripts/validate_memory_atlas_v1_2_home_multiviewport.cjs",
audit:"OpenAIDatabase/scripts/audit_memory_atlas_visual_acceptance.py",
evidence:"OpenAIDatabase/机器治理/证据与日志/remediation/v1_2_r2/browser/after/status.json",
test:"OpenAIDatabase/tests/test_memory_atlas_v1_2_product_identity_contract.py"
};
const [v,a,e,t,ad]=await Promise.all([
 tools.exec_command({cmd:`nl -ba ${paths.validator} | sed -n '760,875p'`,workdir:repo,yield_time_ms:10000,max_output_tokens:12000}),
 tools.exec_command({cmd:`nl -ba ${paths.audit} | sed -n '1,300p'`,workdir:repo,yield_time_ms:10000,max_output_tokens:20000}),
 tools.exec_command({cmd:`rg -n -C 4 \"mobileNavigationKeyboardTraversal|keyboardTraversal|releaseIdentity|defaultSurfaceCopy|status|checks\" '${paths.evidence}'`,workdir:repo,yield_time_ms:10000,max_output_tokens:15000}),
 tools.exec_command({cmd:`nl -ba ${paths.test} | sed -n '1,180p'`,workdir:repo,yield_time_ms:10000,max_output_tokens:10000}),
 tools.exec_command({cmd:`git diff --unified=50 -- ${paths.audit}`,workdir:repo,yield_time_ms:10000,max_output_tokens:20000})
]);
text("VALIDATOR-RUN\n"+v.output); text("AUDIT\n"+a.output); text("EVIDENCE\n"+e.output); text("TEST\n"+t.output); text("AUDIT-DIFF\n"+ad.output);

const repo="[REDACTED_LOCAL_PATH]";
const [a,i,e]=await Promise.all([
 tools.exec_command({cmd:"rg -n -C 3 \"navigation\\.views\\.|label: \\\"(记忆总览|银河星云|主题图谱|ROI 仪表盘|关系图谱|时间轴|贡献图|词云洞察|搜索与复盘|总结与迭代|发生了什么|决定下一步|它们如何关联|哪些主题连在一起|哪里值得继续投入|哪些关系值得复核|最近如何变化|哪些时期最密集|反复出现什么|我想找什么)\\\"\" OpenAIDatabase/scripts/audit_memory_atlas_visual_acceptance.py","workdir":repo,"yield_time_ms":10000,"max_output_tokens":18000}),
 tools.exec_command({cmd:"nl -ba OpenAIDatabase/apps/memory-atlas/src/i18n/zh-CN.ts | sed -n '1,45p'","workdir":repo,"yield_time_ms":10000,"max_output_tokens":5000}),
 tools.exec_command({cmd:"jq '{status, generated_at, results: [.results[] | {name: .viewport.name, status, releaseIdentity, defaultSurfaceCopy, mobileNavigationKeyboard}]}' 'OpenAIDatabase/机器治理/证据与日志/remediation/v1_2_r2/browser/after/status.json'","workdir":repo,"yield_time_ms":10000,"max_output_tokens":20000})
]);
text("AUDIT-LABELS\n"+a.output); text("I18N\n"+i.output); text("EVIDENCE\n"+e.output);

